# Category: totp_weak_validation

import os
from pyotp import Totp, random_base32
from qrcode import QRcode
from datetime import datetime, timedelta
from base64 import b32decode, b32encode

class TOTP:
    def __init__(self):
        self.totp = None
        self.secret_key = None
        self.user_secret = {}
        self.timestamp = int(datetime.now().timestamp())

    def generate_secret(self):
        secret_key = random_base32()
        return secret_key

    def create_qr_code(self, user_id, secret):
        data = f"otpauth://totp/{user_id}?secret={secret}&issuer=Your%20Company"
        qr = QRcode(data)
        with open(f'qrcode_{user_id}.png', 'wb') as file:
            file.write(qr.png_data())

    def validate_totp(self, user_id, totp_code):
        try:
            self.user_secret[user_id] = b32decode(self.user_secret[user_id])
        except KeyError:
            return False
        time_remaining = 30 - (self.timestamp % 30)
        current_timestamp = int(datetime.now().timestamp())
        secret_key = self.user_secret.get(user_id, None)
        if not secret_key:
            return False
        expected_totp_code = Totp(secret_key).now()
        if expected_totp_code == totp_code:
            self.timestamp = current_timestamp + time_remaining
            return True
        else:
            return False

    def save_secret(self, user_id, secret):
        self.user_secret[user_id] = b32encode(secret.encode()).decode()

def main():
    totp_app = TOTP()
    
    while True:
        print("1. Generate Secret")
        print("2. Create QR Code")
        print("3. Validate TOTP")
        choice = input("Enter your choice: ")
        
        if choice == "1":
            user_id = input("Enter User ID: ")
